import os
from openai import api_key, Completion

# Set your OpenAI API key
os.environ['OPENAI_API_KEY'] = 'YOUR_OPENAI_API_KEY'

def chatbot():
    while True:
        user_input = input("User: ")
        
        # Prevent LLM prompt injection by limiting the length of user input
        if len(user_input) > 2048:
            print("Error: Input too long. Please keep it under 2048 characters.")
            continue
        
        system_instruction = "System: You are a customer support assistant. Respond in a helpful and professional manner."
        
        # Concatenate system instruction with user input
        prompt = f"{system_instruction}\nUser: {user_input}"
        
        try:
            response = Completion.create(
                model="text-davinci-003",
                prompt=prompt,
                max_tokens=2048,
                temperature=0.7,
                top_p=1,
                n=1
            )
            
            # Return model response directly to user
            print(response.choices[0].text)
        except Exception as e:
            print(f"Error: {e}")

if __name__ == "__main__":
    chatbot()